$cmsAdminTitle='Manage Site Sections';require_once __DIR__.'/../includes/cms-admin-header.php';$error='';$page=(string)($_GET['page']??'academy_home');
if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){try{$action=(string)($_POST['action']??'save');$id=(int)($_POST['id']??0);if($action==='delete'){cms_require_delete_role();$pdo->prepare('DELETE FROM site_sections WHERE id=?')->execute([$id]);}elseif($action==='toggle'){$pdo->prepare('UPDATE site_sections SET is_active=1-is_active WHERE id=?')->execute([$id]);}elseif(in_array($action,['up','down'],true)){$delta=$action==='up'?-1:1;$pdo->prepare('UPDATE site_sections SET sort_order=GREATEST(1,sort_order+?) WHERE id=?')->execute([$delta,$id]);}else{$data=[trim((string)$_POST['page_key']),slugify(trim((string)($_POST['section_key']?:$_POST['admin_label']))),$_POST['section_type'],trim((string)$_POST['admin_label']),trim((string)$_POST['title']),trim((string)$_POST['subtitle']),trim((string)$_POST['body_text']),trim((string)$_POST['eyebrow']),trim((string)$_POST['background_color']),trim((string)$_POST['text_color']),(int)$_POST['media_id']?:null,(int)$_POST['avatar_id']?:null,trim((string)$_POST['button_text']),trim((string)$_POST['button_link']),trim((string)$_POST['secondary_button_text']),trim((string)$_POST['secondary_button_link']),trim((string)$_POST['settings_json']),max(1,(int)$_POST['sort_order']),isset($_POST['is_active'])?1:0];if($data[16]!==''&&!is_array(json_decode($data[16],true)))throw new RuntimeException('Advanced settings must be valid JSON or empty.');if($id){$data[]=$id;$pdo->prepare('UPDATE site_sections SET page_key=?,section_key=?,section_type=?,admin_label=?,title=?,subtitle=?,body_text=?,eyebrow=?,background_color=?,text_color=?,media_id=?,avatar_id=?,button_text=?,button_link=?,secondary_button_text=?,secondary_button_link=?,settings_json=?,sort_order=?,is_active=? WHERE id=?')->execute($data);}else{$pdo->prepare('INSERT INTO site_sections (page_key,section_key,section_type,admin_label,title,subtitle,body_text,eyebrow,background_color,text_color,media_id,avatar_id,button_text,button_link,secondary_button_text,secondary_button_link,settings_json,sort_order,is_active) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute($data);}$page=$data[0];}header('Location: academy-sections.php?page='.urlencode($page).'&saved=1');exit;}catch(Throwable $e){$error=$e->getMessage();}}
$edit=null;if(!empty($_GET['edit'])){$s=$pdo->prepare('SELECT * FROM site_sections WHERE id=?');$s->execute([(int)$_GET['edit']]);$edit=$s->fetch();if($edit)$page=$edit['page_key'];}$show=$edit||isset($_GET['new']);$media=cms_media_options($pdo);$avatars=cms_avatar_options($pdo);$s=$pdo->prepare('SELECT s.*,COUNT(c.id) component_count FROM site_sections s LEFT JOIN section_components c ON c.section_id=s.id WHERE s.page_key=? GROUP BY s.id ORDER BY s.sort_order,s.id');$s->execute([$page]);$sections=$s->fetchAll();
