abel>Reusable media<select class="form-select" name="media_id"><option value="0">No media</option><?php foreach($media as $m):?><option value="<?=(int)$m['id']?>" <?=(int)($edit['media_id']??0)===(int)$m['id']?'selected':''?>><?=e($m['title'].' · '.$m['file_type'])?></option><?php endforeach?></select></label><label>Animated avatar<select class="form-select" name="avatar_id"><option value="0">Default code avatar</option><?php foreach($avatars as $a):?><option value="<?=(int)$a['id']?>" <?=(int)($edit['avatar_id']??0)===(int)$a['id']?'selected':''?>><?=e($a['name'].' · '.$a['learner_type'])?></option><?php endforeach?></select></label><label>Background color<input class="form-control" name="background_color" value="<?=e($edit['background_color']??'')?>" placeholder="#080b12"></label><label>Text color<input class="form-control" name="text_color" value="<?=e($edit['text_color']??'')?>" placeholder="#ffffff"></label><label>Display order<input class="form-control" type="number" min="1" name="sort_order" value="<?=(int)($edit['sort_order']??1)?>"></label><label class="d-flex gap-2 align-items-center"><input type="checkbox" name="is_active" value="1" <?=($edit['is_active']??1)?'checked':''?>> Visible on frontend</label><label class="wide">Advanced settings JSON<textarea class="form-control font-monospace" name="settings_json"><?=e($edit['settings_json']??'')?></textarea></label><div class="wide"><button class="btn btn-premium" name="action" value="save">Save section</button> <a class="btn btn-outline-light" href="?page=<?=urlencode($page)?>">Cancel</a></div></form><?php endif?>
